function ChartTipFn(dark) {
  return function(p) {
    if (!p.active || !p.payload || !p.payload.length) return null;
    var port = 0;
    var cont = 0;
    p.payload.forEach(function(v) {
      if (v.dataKey === "portfolio") port = v.value;
      if (v.dataKey === "contributed") cont = v.value;
    });
    var gain = port - cont;
    var gPct = cont > 0 ? ((gain / cont) * 100).toFixed(1) : "0";
    var tipBox = {
      background: dark ? "rgba(10,14,26,0.95)" : "rgba(255,255,255,0.95)",
      border: "1px solid " + (dark ? "#1e3a5f" : "#cbd5e1"),
      borderRadius: 14,
      padding: "16px 20px",
      minWidth: 180,
      boxShadow: dark ? "none" : "0 4px 20px rgba(0,0,0,0.1)"
    };
    return (
      <div style={tipBox}>
        {p.label ? <div style={{color: dark ? "#64748b" : "#94a3b8", fontSize: 10, fontWeight: 600, textTransform: "uppercase", marginBottom: 10}}>{p.label}</div> : null}
        <div style={{marginBottom: 6}}>
          <div style={{fontSize: 10, color: dark ? "#94a3b8" : "#64748b"}}>Portfolio</div>
          <div style={{fontSize: 16, fontWeight: 700, color: "#22c55e"}}>{fmt(port)}</div>
        </div>
        <div style={{marginBottom: 8}}>
          <div style={{fontSize: 10, color: dark ? "#94a3b8" : "#64748b"}}>Contributed</div>
          <div style={{fontSize: 14, fontWeight: 600, color: "#3b82f6"}}>{fmt(cont)}</div>
        </div>
        <div style={{borderTop: "1px solid " + (dark ? "#1e293b" : "#e2e8f0"), paddingTop: 8}}>
          <div style={{fontSize: 10, color: dark ? "#94a3b8" : "#64748b", marginBottom: 2}}>Gain</div>
          <div style={{fontSize: 14, fontWeight: 700, color: gain >= 0 ? "#22c55e" : "#ef4444"}}>{gain >= 0 ? "↑ " : "↓ "}{fmt(Math.round(Math.abs(gain)))} ({gPct}%)</div>
        </div>
      </div>
    );
  };
}
